type EWFlag struct {
	mu       sync.RWMutex
	dots     map[string]uint64
	counters map[string]uint64
}

// NewEWFlag creates a new enable-wins flag (initially disabled).
func NewEWFlag() *EWFlag {
	return &EWFlag{
		dots:     make(map[string]uint64),
		counters: make(map[string]uint64),
	}
}

// Enable enables the flag from the given node.
func (f *EWFlag) Enable(nodeID string) {
	f.mu.Lock()
	defer f.mu.Unlock()
	f.counters[nodeID]++
	f.dots[nodeID] = f.counters[nodeID]
}

// Disable disables the flag by removing all observed dots.
func (f *EWFlag) Disable() {
	f.mu.Lock()
	defer f.mu.Unlock()
	f.dots = make(map[string]uint64)
}

// Value returns true if the flag is enabled (has any active dots).
func (f *EWFlag) Value() bool {
	f.mu.RLock()
	defer f.mu.RUnlock()
	return len(f.dots) > 0
}

// Merge incorporates another EWFlag's state.
// A dot is removed only when the other replica's causal context proves it
// observed that dot and no longer carries it as active.
func (f *EWFlag) Merge(other *EWFlag) {
	if f == other {
		return
	}

	f.mu.Lock()
	defer f.mu.Unlock()
	other.mu.RLock()
	defer other.mu.RUnlock()

	mergedDots := make(map[string]uint64, len(f.dots)+len(other.dots))
	for nodeID, localDot := range f.dots {
		if otherDot, ok := other.dots[nodeID]; ok && otherDot == localDot {
			mergedDots[nodeID] = localDot
			continue
		}
		if other.counters[nodeID] < localDot {
			mergedDots[nodeID] = localDot
		}
	}
	for nodeID, otherDot := range other.dots {
		if localDot, ok := f.dots[nodeID]; ok && localDot == otherDot {
			mergedDots[nodeID] = otherDot
			continue
		}
		if f.counters[nodeID] < otherDot {
			if currentDot, ok := mergedDots[nodeID]; !ok || otherDot > currentDot {
				mergedDots[nodeID] = otherDot
			}
		}
	}
	f.dots = mergedDots

	for nodeID, otherCounter := range other.counters {
		if otherCounter > f.counters[nodeID] {
			f.counters[nodeID] = otherCounter
		}
	}
}

